/**
 * Muestra la sección de navegación seleccionada
 * @param {string} sectionId - ID de la sección a mostrar ('facturas' o 'csf')
 * @param {HTMLElement} clickedLink - Elemento nav-link que fue clicado
 */
function showSection(sectionId, clickedLink) {
    // Ocultar todas las secciones
    document.querySelectorAll('.page-section').forEach(function(section) {
        section.classList.remove('active');
    });

    // Desactivar todos los nav-links
    document.querySelectorAll('.nav-link').forEach(function(link) {
        link.classList.remove('active');
    });

    // Mostrar la sección seleccionada y marcar el link activo
    var target = document.getElementById('section-' + sectionId);
    if (target) {
        target.classList.add('active');
    }
    if (clickedLink) {
        clickedLink.classList.add('active');
    }
}

