/**
 * Inicializa el formulario y sus eventos
 */
function initForm() {
    const form = document.getElementById('consultaForm');
    
    form.addEventListener('submit', async function(e) {
        e.preventDefault();
        await submitForm();
    });

    // Actualizar previews de fechas
    document.getElementById('fecha_inicial').addEventListener('change', updateFechaPreviews);
    document.getElementById('fecha_final').addEventListener('change', updateFechaPreviews);
}

/**
 * Formatea fecha ISO para la API
 */
function formatFechaParaAPI(fechaISO) {
    const fechaConEspacio = fechaISO.replace('T', ' ');
    return fechaConEspacio.length === 16 ? fechaConEspacio + ':00' : fechaConEspacio;
}

/**
 * Actualiza las previsualizaciones de formato de fecha
 */
function updateFechaPreviews() {
    const fechaInicial = document.getElementById('fecha_inicial').value;
    const fechaFinal = document.getElementById('fecha_final').value;
    
    document.getElementById('fecha_inicial_preview').textContent = 
        'Formato enviado: ' + formatFechaParaAPI(fechaInicial);
    document.getElementById('fecha_final_preview').textContent = 
        'Formato enviado: ' + formatFechaParaAPI(fechaFinal);
}

/**
 * Envía el formulario
 */
async function submitForm() {
    const form = document.getElementById('consultaForm');
    const submitBtn = document.getElementById('submitBtn');
    const btnText = document.getElementById('btnText');
    const btnSpinner = document.getElementById('btnSpinner');
    
    // Mostrar loading
    submitBtn.disabled = true;
    btnText.classList.add('hidden');
    btnSpinner.classList.remove('hidden');
    hideAlert();

    try {
        const formData = new FormData(form);
        
        // Convertir checkbox a string
        formData.set('descarga_comprobantes', 
            document.getElementById('descarga_comprobantes').checked ? 'true' : 'false');

        const response = await fetch('ajax/consultar.php', {
            method: 'POST',
            body: formData
        });

        const result = await response.json();

        if (result.success) {
            showAlert('success', result.message || 'Consulta exitosa');
            displayResults(result.data);
            
            // Guardar requestId para reusar sesión
            if (result.data?.requestId) {
                document.getElementById('request_id').value = result.data.requestId;
            }
        } else {
            showErrorModal('Error en la consulta', result.error || 'Error desconocido', result);
        }
    } catch (error) {
        showErrorModal('Error inesperado', 'Error inesperado al realizar la consulta', error);
    } finally {
        // Ocultar loading
        submitBtn.disabled = false;
        btnText.classList.remove('hidden');
        btnSpinner.classList.add('hidden');
    }
}

