/**
 * Muestra los resultados de la consulta
 */
function displayResults(data) {
    const card = document.getElementById('resultadosCard');
    const content = document.getElementById('resultadosContent');
    
    card.style.display = 'block';
    
    // Manejar error de la API
    if (data.success === false) {
        content.innerHTML = `
            <div class="alert alert-danger">
                <strong>Error en la consulta</strong>
                <p>${data.errorMessage || 'Error desconocido en la respuesta de la API'}</p>
                ${data.requestId ? `<small>Request ID: ${data.requestId}</small>` : ''}
            </div>
        `;
        document.getElementById('statusBadge').className = 'badge badge-danger';
        document.getElementById('statusBadge').textContent = 'Error';
        return;
    }

    // Extraer comprobantes
    facturas = data.comprobantes || [];
    currentPage = 1;
    expandedRows = new Set();
    
    // Actualizar badges
    document.getElementById('totalFacturas').textContent = `${data.count || facturas.length} factura(s) encontrada(s)`;
    
    // Generated by Copilot - Mostrar/ocultar botón de descargar todos
    const downloadAllBtn = document.getElementById('downloadAllBtn');
    const facturasConContent = facturas.filter(f => f.content);
    if (facturasConContent.length > 0) {
        downloadAllBtn.style.display = 'inline-flex';
        downloadAllBtn.textContent = `⬇ Descargar ${facturasConContent.length} XML`;
    } else {
        downloadAllBtn.style.display = 'none';
    }
    document.getElementById('statusBadge').className = data.success ? 'badge badge-success' : 'badge badge-danger';
    document.getElementById('statusBadge').textContent = data.success ? 'Éxito' : 'Error';
    
    if (data.requestId) {
        document.getElementById('requestIdDisplay').textContent = 'Request ID: ' + data.requestId;
    }

    if (facturas.length === 0) {
        content.innerHTML = `
            <div class="alert alert-warning">
                No se encontraron facturas con los criterios especificados.
            </div>
        `;
        return;
    }

    renderTable();
}

