/**
 * Inicializa el formulario de CSF y sus eventos
 */
function initCsfForm() {
    const form = document.getElementById('csfForm');
    if (!form) return;
    form.addEventListener('submit', async function(e) {
        e.preventDefault();
        await submitCsfForm();
    });
}

/**
 * Envía el formulario de CSF a la API
 */
async function submitCsfForm() {
    const form        = document.getElementById('csfForm');
    const submitBtn   = document.getElementById('csfSubmitBtn');
    const btnText     = document.getElementById('csfBtnText');
    const btnSpinner  = document.getElementById('csfBtnSpinner');

    // Mostrar loading
    submitBtn.disabled = true;
    btnText.classList.add('hidden');
    btnSpinner.classList.remove('hidden');
    csfHideAlert();

    // Ocultar resultado anterior
    const resultCard = document.getElementById('csfResultadoCard');
    if (resultCard) resultCard.style.display = 'none';

    try {
        const formData = new FormData(form);

        const response = await fetch('ajax/consultar_csf.php', {
            method: 'POST',
            body: formData
        });

        const result = await response.json();

        if (result.success) {
            csfDisplayResult(result);
        } else {
            csfDisplayError(result.error || 'Error al descargar la CSF');
        }
    } catch (error) {
        csfDisplayError('Error inesperado al realizar la descarga: ' + error.message);
    } finally {
        submitBtn.disabled = false;
        btnText.classList.remove('hidden');
        btnSpinner.classList.add('hidden');
    }
}

