// ============================================================

/**
 * Inicializa el formulario de Opinión de Cumplimiento
 */
function initOcForm() {
    const form = document.getElementById('ocForm');
    if (!form) return;
    form.addEventListener('submit', async function(e) {
        e.preventDefault();
        await submitOcForm();
    });
}

/**
 * Envía el formulario de Opinión de Cumplimiento a la API
 */
async function submitOcForm() {
    const form       = document.getElementById('ocForm');
    const submitBtn  = document.getElementById('ocSubmitBtn');
    const btnText    = document.getElementById('ocBtnText');
    const btnSpinner = document.getElementById('ocBtnSpinner');

    submitBtn.disabled = true;
    btnText.classList.add('hidden');
    btnSpinner.classList.remove('hidden');
    ocHideAlert();

    // Ocultar resultado anterior
    const resultCard = document.getElementById('ocResultadoCard');
    if (resultCard) resultCard.style.display = 'none';

    try {
        const formData = new FormData(form);

        const response = await fetch('ajax/consultar_oc.php', {
            method: 'POST',
            body: formData
        });

        const result = await response.json();

        if (result.success) {
            ocDisplayResult(result);
        } else {
            ocDisplayError(result.error || 'Error al consultar la Opinión de Cumplimiento');
        }
    } catch (error) {
        ocDisplayError('Error inesperado al realizar la consulta: ' + error.message);
    } finally {
        submitBtn.disabled = false;
        btnText.classList.remove('hidden');
        btnSpinner.classList.add('hidden');
    }
}

/**
 * Muestra una alerta en la sección OC
 * @param {string} type - 'success' | 'danger' | 'warning'
 * @param {string} message
 */
function ocShowAlert(type, message) {
    const container = document.getElementById('oc-alertContainer');
    if (!container) return;
    container.innerHTML = `
        <div class="alert alert-${type}">
            ${message}
            <button type="button" style="float:right;background:none;border:none;cursor:pointer;font-size:18px;" onclick="ocHideAlert()">&times;</button>
        </div>`;
}

/**
 * Oculta la alerta de la sección OC
 */
function ocHideAlert() {
    const container = document.getElementById('oc-alertContainer');
    if (container) container.innerHTML = '';
}

/**
 * Muestra un error en el card de resultados OC
 * @param {string} message
 */
function ocDisplayError(message) {
    const card    = document.getElementById('ocResultadoCard');
    const content = document.getElementById('ocResultadoContent');
    card.style.display = 'block';
    content.innerHTML = `
        <div class="alert alert-danger">
            <strong>Error al consultar la Opinión de Cumplimiento</strong>
            <p style="margin:10px 0 0;white-space:pre-wrap;">${message}</p>
        </div>`;
}

/**
 * Muestra el resultado de la Opinión de Cumplimiento
 * @param {object} data - Respuesta completa de la API
 */
function ocDisplayResult(data) {
    const card    = document.getElementById('ocResultadoCard');
    const content = document.getElementById('ocResultadoContent');

    card.style.display = 'block';

    if (!data) {
        content.innerHTML = '<div class="alert alert-warning">La API no devolvió datos.</div>';
        return;
    }

    // Respuesta PDF en base64
    if (data.is_pdf && data.pdf_base64) {
        const filename  = data.filename || 'opinion_cumplimiento.pdf';
        const byteChars = atob(data.pdf_base64);
        const byteNums  = new Array(byteChars.length);
        for (let i = 0; i < byteChars.length; i++) {
            byteNums[i] = byteChars.charCodeAt(i);
        }
        const blob = new Blob([new Uint8Array(byteNums)], { type: 'application/pdf' });
        const url  = URL.createObjectURL(blob);

        content.innerHTML = `
            <div class="alert alert-success">${data.message || 'Opinión de Cumplimiento descargada correctamente.'}</div>
            <div style="text-align:center;margin-top:16px;gap:12px;display:flex;justify-content:center;">
                <a class="btn btn-success" href="${url}" download="${filename}">
                    &#128190; Descargar PDF
                </a>
                <a class="btn btn-primary" href="${url}" target="_blank" rel="noopener">
                    &#128065; Ver PDF
                </a>
            </div>`;

        // Disparar descarga automática
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        return;
    }

    // Respuesta JSON u otro formato — mostrar crudo para depuración
    content.innerHTML = `
        <div class="alert alert-warning">Respuesta recibida. Revisa los detalles:</div>
        <pre style="background:#f8f9fa;padding:16px;border-radius:4px;overflow:auto;">${JSON.stringify(data, null, 2)}</pre>`;
}
